var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"왕이시여, 잠시 연주를 멈추어도 될지요.","JPN":"王様、しばらく演奏を中断してもよろしいでしょうか。","ENG":"My lord, may I request an intermission?","TWN":"我的王，可以暫時停止演奏嗎。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이유를 들어 봐도 될까요, 네퀴티아?","JPN":"理由を聞いてもいいですか？　ネキティア。","ENG":"May we hear why, Nequitia?","TWN":"能說出你的理由嗎，莉奎蒂亞？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이대로는 왕의 뜻에 걸맞은 음률을 자아내기에 부족함이 있군요.","JPN":"今の状態で王様の意志に相応しい音律を奏でるのは少々無理があります。","ENG":"I fear that the song is unfitting of your request, my lord.","TWN":"照這樣下去，還不足以發出符合王旨意的音律。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"정비할 시간을 허락해 주신다면 최선을 다해 조율하도록 하겠습니다.","JPN":"整備する時間をお許しいただけるのなら、一生懸命調律いたします。","ENG":"With your permission, I will do my best to retune my instruments.","TWN":"如果你同意給我調整的時間，我會盡最大努力去協調。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아하, 그래서군요. 어쩐지 반응이 너무 늦다 했어요.","JPN":"ああ、だからなのですね。反応が遅すぎると思いました。","ENG":"Oh, that's why. No wonder the response was late.","TWN":"哈，原來是因為這樣。怪不得反應太慢了。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그런 문제라면 얼마든지 시간을 할애하셔도 괜찮답니다. 의식은 거의 완성되어 가니까요.","JPN":"そのような問題でしたら、いくら時間を割いても構いません。儀式はほぼ完成されている状態ですから。","ENG":"If that is the case, we will give you as much time as you require. The ritual is nearly complete.","TWN":"如果只是這種問題，那你花多少時間都沒關係。因為儀式就快完成了。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"채비는 어디까지나 레지나 님께서 돌아오실 때까지만 마칠 수 있으면 돼요.","JPN":"レジーナ様がお戻りになる時までに準備ができていれば問題ありません。","ENG":"Nonetheless, you must finish before Miss Regina returns.","TWN":"只要在蕾佳娜回來之前，做好一切準備就可以。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"허락해 주셔서 감사합니다. 그럼 잠시.","JPN":"お許しいただき、ありがとうございます。それでは。","ENG":"Thank you, my lord. I will be prompt.","TWN":"謝謝你的允許，那我先暫停一下。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"루나, 이리 오세요.","JPN":"ルナ、こちらにいらっしゃい。","ENG":"Luna, please come over here.","TWN":"露娜，過來。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지, 지휘자님…….","JPN":"ま、マエストロ……","ENG":"C-Chief Conductor...?","TWN":"指…指揮家……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그새 인간과 정이 드셨나요?","JPN":"もう人間と馴染んでしまったのですか？","ENG":"Have you already developed feelings for humans these past few days?","TWN":"你這麼快就和人類產生感情了嗎？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"셰나와 카르멘에게 들키지 않으면서 음정을 어긋나게 하다니……","JPN":"シェナとカルメンに悟られずに、ずれた音程を出すとは……","ENG":"You were playing out of tune without Shena or Carmen noticing...","TWN":"你居然背著世娜和卡門偷偷吹錯旋律……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"시기를 늦추려고 애쓰는 꼴이 참으로 갸륵하군요.","JPN":"どうにか時期を遅らせようとしている姿が、とても健気ですね。","ENG":"It's pathetic seeing you struggle to delay the ritual.","TWN":"你努力拖延時間的樣子，真是讓人敬佩。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"대답해 보세요. 제가 눈이 어두워 모르리라고 생각했나요.","JPN":"答えなさい。私の目が見えないから、知らないとでも思ったのですか？","ENG":"Answer me. Or did you think I wouldn't notice because I am blind?","TWN":"回答我。你以為我眼睛瞎了，就不能察覺嗎。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아, 아니요! 절대 그렇지 않아요!","JPN":"い、いいえ！　絶対そんなことは！","ENG":"N-no! I would never!","TWN":"不…不是的！絕對不是那樣的！"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그렇다면 당신이 무엇인지 말씀해 보세요.","JPN":"でしたら、あなたが何者か言ってごらんなさい。","ENG":"Then will you remind me who you are again?","TWN":"那你說說看，自己到底是誰。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"저, 저는 엘리시움 필하모닉의 나팔수로서……","JPN":"あ、アタシはエリシウムフィルハーモニーのトランぺット奏者で……","ENG":"I'm... I'm the trumpeter of Elysium Philharmonic...","TWN":"我、我是愛樂組織的小號手……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"최고 지휘자님의 악기…… 입니다…….","JPN":"マエストロの楽器……です……","ENG":"and the Chief Conductor's... instrument...","TWN":"首席指揮家的樂器……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};